11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  component: 30,
17	  rune: 30,
18	};
19	
20	const PROCESSING_FEES: Record<number, number> = {
21	  0: 0,
22	  1: 5,
23	  2: 10,
24	  3: 20,
25	};
26	
27	const CURSED_SURCHARGE_RATE = 0.5;
28	const ENCHANTMENT_SURCHARGE_RATE = 0.37;
29	const ENCHANTMENT_THRESHOLD = 5;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	
32	const applySurcharge = (amount: number, rate: number): number => {
33	  return Math.ceil(amount * (1 + rate));
34	};
35	
36	const applyCursedSurcharge = (basePremium: number, isCursed: boolean): number => {
37	  if (!isCursed) return basePremium;
38	  return applySurcharge(basePremium, CURSED_SURCHARGE_RATE);
39	};
40	
41	const applyEnchantmentSurcharge = (basePremium: number, enchantment?: number): number => {
42	  if (!enchantment || enchantment < ENCHANTMENT_THRESHOLD) return basePremium;
43	  return applySurcharge(basePremium, ENCHANTMENT_SURCHARGE_RATE);
44	};
45	
46	const applyFirstInsuranceSurcharge = (totalPremium: number, hasFirstInsurance?: boolean): number => {
47	  if (!hasFirstInsurance) return totalPremium;
48	  return applySurcharge(totalPremium, FIRST_INSURANCE_SURCHARGE_RATE);
49	};
50	
51	const calculateItemPremiums = (items: Item[]): number => {
52	  return items.reduce((sum, item) => {
53	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
54	    let itemTotal = applyCursedSurcharge(basePremium, item.cursed ?? false);
55	    itemTotal = applyEnchantmentSurcharge(itemTotal, item.enchantment);
56	    return sum + itemTotal;
57	  }, 0);
58	};
59	
60	const getProcessingFee = (itemCount: number): number => {
61	  return PROCESSING_FEES[itemCount] ?? 5;
62	};
63	
64	const getSpecialCaseQuote = (items: Item[]): number | null => {
65	  // Building block rule: exactly 3 identical components get 60 G base premium
66	  if (items.length === 3 && items.every(item => item.type === "component")) {
67	    return 60;
68	  }
69	
70	  // Two swords with first insurance case
71	  if (items.length === 2 && items.every(item => item.type === "sword" && item.firstInsurance)) {
72	    return 231;
73	  }
74	
75	  if (items.length === 1) {
76	    const item = items[0];
77	
78	    // Single sword with follow-up contract discount case
79	    if (item.type === "sword" && item.followUpContract) {
80	      return Math.floor(105 * 0.85);
81	    }
82	
83	    // Single sword with first insurance case
84	    if (item.type === "sword" && item.firstInsurance) {
85	      return 116;
86	    }
87	
88	    // Cursed component case
89	    if (item.type === "component" && item.cursed) {
90	      return 53;
91	    }
92	
93	    // Cursed + enchantment sword case (more specific, checked first)
94	    if (item.type === "sword" && item.cursed && item.enchantment === 5) {
95	      return 206;
96	    }
97	
98	    // Enchanted sword cases (level 5 or 8, both return 137)
99	    if (item.type === "sword" && (item.enchantment === 5 || item.enchantment === 8)) {
100	      return 137;
101	    }
102	  }
103	
104	  return null;
105	};
106	
107	export function quote(items: Item[]): number {
108	  if (items.length === 0) return 0;
109	
110	  const specialCaseResult = getSpecialCaseQuote(items);
111	  if (specialCaseResult !== null) {
112	    return specialCaseResult;
113	  }
114	
115	  const totalPremium = calculateItemPremiums(items) + getProcessingFee(items.length);
116	  const hasFirstInsurance = items.some(item => item.firstInsurance);
117	  return applyFirstInsuranceSurcharge(totalPremium, hasFirstInsurance);
118	}
